import json

# Load the full business data
with open('/tmp/tmpu2uvh7n1.json', 'r') as f:
    businesses = json.load(f)

# Count total businesses
print("Total businesses:", len(businesses))

# Look for WiFi information in attributes
wifi_yes = []
wifi_no = []
wifi_free = []
wifi_missing = []

for biz in businesses:
    attrs = biz.get('attributes')
    if isinstance(attrs, dict):
        wifi = attrs.get('WiFi')
        if wifi:
            if 'yes' in str(wifi).lower():
                wifi_yes.append(biz)
            elif 'no' in str(wifi).lower():
                wifi_no.append(biz)
            elif 'free' in str(wifi).lower():
                wifi_free.append(biz)
            else:
                # Check if it's u'free' format
                if str(wifi) == "u'free'":
                    wifi_free.append(biz)
                elif str(wifi) == "u'no'":
                    wifi_no.append(biz)
                else:
                    wifi_missing.append(biz)
        else:
            wifi_missing.append(biz)
    else:
        wifi_missing.append(biz)

print("WiFi 'free':", len(wifi_free))
print("WiFi 'yes':", len(wifi_yes))
print("WiFi 'no':", len(wifi_no))
print("WiFi missing:", len(wifi_missing))

# Extract state information from descriptions
import re

def extract_state(description):
    if not description or description == "None":
        return None

    # Look for state abbreviations (e.g., "CA", "FL", "NY")
    match = re.search(r'\b([A-Z]{2})\b', description)
    if match:
        return match.group(1)
    return None

# Test on a few examples
print("\nTesting state extraction:")
for biz in businesses[:5]:
    state = extract_state(biz.get('description', ''))
    print(f"{biz['name']}: {state}")

print("__RESULT__:")
print(json.dumps({"wifi_free": len(wifi_free), "wifi_yes": len(wifi_yes), "total_businesses": len(businesses)}))

